import { useSelector, useDispatch } from 'react-redux';
import { Link } from 'react-router-dom';
import { logout } from '../redux/actions/authActions';

const Navbar = () => {
  const user = useSelector(state => state.auth.user);
  const dispatch = useDispatch();

  return (
    <nav>
      <Link to="/">Главная</Link>
      {!user && <Link to="/login">Вход</Link>}
      {user?.role === 'admin' && <Link to="/manage-users">Пользователи</Link>}
      {user?.role === 'teacher' && <Link to="/grade">Оценки</Link>}
      {user?.role === 'student' && <Link to="/my-grades">Мои оценки</Link>}
      {user && <button onClick={() => dispatch(logout())}>Выйти</button>}
    </nav>
  );
};

export default Navbar;
